```c
static void nr_dlsch_layer_demapping(int16_t *llr_cw[2],
                                     uint8_t Nl,
                                     uint8_t mod_order,
                                     uint32_t length,
                                     int32_t codeword_TB0,
                                     int32_t codeword_TB1,
                                     int16_t *llr_layers[NR_MAX_NB_LAYERS]) {

  // Clear stale state for inactive codewords
  if (codeword_TB0 == -1 && llr_cw[0] != NULL) {
    memset(llr_cw[0], 0, length * sizeof(int16_t));
  }
  if (codeword_TB1 == -1 && llr_cw[1] != NULL) {
    memset(llr_cw[1], 0, length * sizeof(int16_t));
  }

  switch (Nl) {
    case 1:
      if (codeword_TB1 == -1)
        memcpy(llr_cw[0], llr_layers[0], (length)*sizeof(int16_t));
      else if (codeword_TB0 == -1)
        memcpy(llr_cw[1], llr_layers[0], (length)*sizeof(int16_t));
      break;

    case 2:
    case 3:
    case 4:
      for (int i=0; i<(length/Nl/mod_order); i++){
        for (int l=0; l<Nl; l++) {
          for (int m=0; m<mod_order; m++){
            if (codeword_TB1 == -1)
              llr_cw[0][Nl*mod_order*i+l*mod_order+m] = llr_layers[l][i*mod_order+m];
            else if (codeword_TB0 == -1)
              llr_cw[1][Nl*mod_order*i+l*mod_order+m] = llr_layers[l][i*mod_order+m];
          }
        }
      }
      break;

    default:
      AssertFatal(0, "Not supported number of layers %d\n", Nl);
  }
}
